import 'package:flutter_jailbreak_detection/flutter_jailbreak_detection.dart';

class SecurityService {
  Future<bool> isDeviceSecure() async {
    final jailbroken = await FlutterJailbreakDetection.jailbroken;
    final developerMode = await FlutterJailbreakDetection.developerMode;
    return !jailbroken && !developerMode;
  }

  Future<void> enforceSecurityPolicy() async {
    if (!await isDeviceSecure()) {
      // Warn user or restrict features
      showSecurityWarning();
    }
  }
}

final localAuth = LocalAuthentication();

Future<bool> authenticateUser() async {
  final canCheck = await localAuth.canCheckBiometrics;
  final isDeviceSupported = await localAuth.isDeviceSupported();

  if (!canCheck || !isDeviceSupported) return false;

  return await localAuth.authenticate(
    localizedReason: 'Verify your identity to continue',
    options: const AuthenticationOptions(
      stickyAuth: true,
      biometricOnly: false, // Allow PIN fallback
    ),
  );
}

// GoRouter with auth guard
GoRoute(
  path: '/order/:id',
  redirect: (context, state) {
    final isLoggedIn = ref.read(authProvider).isAuthenticated;
    if (!isLoggedIn) return '/login?redirect=${state.matchedLocation}';

    // Validate parameter
    final orderId = state.pathParameters['id'];
    if (orderId == null || !RegExp(r'^[a-zA-Z0-9-]+$').hasMatch(orderId)) {
      return '/error';
    }
    return null;
  },
  builder: (context, state) => OrderDetailScreen(id: state.pathParameters['id']!),
)

