class InputValidator {
  static String? validateEmail(String? value) {
    if (value == null || value.isEmpty) return 'Email is required';
    if (!RegExp(r'^[\w-\.]+@[\w-]+\.[a-z]{2,}$').hasMatch(value)) {
      return 'Invalid email format';
    }
    if (value.length > 254) return 'Email too long';
    return null;
  }

  static String? sanitizeInput(String input) {
    return input
      .replaceAll(RegExp(r'<[^>]*>'), '') // Strip HTML
      .replaceAll(RegExp(r'[\x00-\x1F]'), '') // Strip control chars
      .trim();
  }
}

class AuthTokenManager {
  final FlutterSecureStorage _storage;

  Future<String?> getValidToken() async {
    final token = await _storage.read(key: 'access_token');
    if (token == null) return null;

    if (_isExpired(token)) {
      final refreshToken = await _storage.read(key: 'refresh_token');
      if (refreshToken == null) return null;
      return await _refreshAccessToken(refreshToken);
    }
    return token;
  }

  Future<void> logout() async {
    await _revokeTokenOnServer();
    await _storage.deleteAll(); // Clear all stored tokens
  }
}

